import sys
import os
import shutil

# Global target path for runtime installations
target_dir = ""

def init_manager(path):
    global target_dir
    target_dir = path
    if not os.path.exists(target_dir):
        os.makedirs(target_dir)
    if target_dir not in sys.path:
        sys.path.append(target_dir)

def install_package(name):
    import pip
    try:
        # Using pip internal main to run installation
        from pip._internal import main as pip_main
        # --target redirects the installation to our writable directory
        # --no-cache-dir saves space on mobile devices
        exit_code = pip_main(['install', '--target', target_dir, '--no-cache-dir', '--quiet', name])

        if exit_code == 0:
            return f"Successfully installed {name}"
        else:
            return f"Pip failed with exit code {exit_code}"
    except Exception as e:
        return f"Installation Error: {str(e)}"

def list_installed():
    if not os.path.exists(target_dir): return []
    # Basic scan for directories that aren't metadata
    return sorted([d for d in os.listdir(target_dir) if os.path.isdir(os.path.join(target_dir, d)) and not d.endswith(('.dist-info', '.egg-info', '__pycache__'))])

def uninstall_package(name):
    try:
        # Simplified uninstall by removing the directory and its metadata
        count = 0
        for d in os.listdir(target_dir):
            if d.lower().startswith(name.lower()):
                shutil.rmtree(os.path.join(target_dir, d))
                count += 1
        return f"Removed {name} and related metadata folders." if count > 0 else f"Package {name} not found."
    except Exception as e:
        return f"Uninstall Error: {str(e)}"

