@Composable
fun PipManagerScreen() {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val python = Python.getInstance()
    val pipManager = python.getModule("pip_manager")

    var packageName by remember { mutableStateOf("") }
    var installedPackages by remember { mutableStateOf(listOf<String>()) }
    var isProcessing by remember { mutableStateOf(false) }

    val refreshList = { 
        installedPackages = pipManager.callAttr("list_installed").asList().map { it.toString() }
    }

    LaunchedEffect(Unit) { refreshList() }

    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("Pip Package Manager", style = MaterialTheme.typography.headlineSmall)
        Text("Pure-Python packages only. C-extensions require rebuild.", style = MaterialTheme.typography.bodySmall, color = Color.Gray)

        Spacer(modifier = Modifier.height(16.dp))

        Row(verticalAlignment = Alignment.CenterVertically) {
            TextField(
                value = packageName,
                onValueChange = { packageName = it },
                modifier = Modifier.weight(1f),
                placeholder = { Text("e.g. requests") },
                singleLine = true,
                enabled = !isProcessing
            )
            Spacer(modifier = Modifier.width(8.dp))
            Button(
                onClick = {
                    scope.launch(Dispatchers.IO) {
                        isProcessing = true
                        val result = pipManager.callAttr("install_package", packageName).toString()
                        withContext(Dispatchers.Main) {
                            Toast.makeText(context, result, Toast.LENGTH_LONG).show()
                            packageName = ""
                            refreshList()
                            isProcessing = false
                        }
                    }
                },
                enabled = !isProcessing && packageName.isNotBlank()
            ) {
                if (isProcessing) CircularProgressIndicator(modifier = Modifier.size(16.dp), strokeWidth = 2.dp) 
                else Text("Install")
            }
        }

        Spacer(modifier = Modifier.height(24.dp))
        Text("Installed in Runtime Context", style = MaterialTheme.typography.titleMedium)
        HorizontalDivider(modifier = Modifier.padding(vertical = 8.dp))

        LazyColumn(modifier = Modifier.weight(1f)) {
            items(installedPackages) { pkg ->
                Row(
                    modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(pkg, fontFamily = FontFamily.Monospace)
                    IconButton(onClick = {
                        scope.launch(Dispatchers.IO) {
                            isProcessing = true
                            pipManager.callAttr("uninstall_package", pkg)
                            withContext(Dispatchers.Main) {
                                refreshList()
                                isProcessing = false
                            }
                        }
                    }, enabled = !isProcessing) {
                        Icon(Icons.Default.Delete, contentDescription = "Uninstall", tint = Color.Red.copy(alpha = 0.6f))
                    }
                }
            }
        }
    }
}

